using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

/// <summary>
/// Server-side implementation that accesses data directly (in-memory store for demo purposes).
/// In production, replace with EF Core / database access.
/// </summary>
public class ServerShipmentService : IShipmentService
{
    private static readonly List<ShipmentDto> Shipments = new()
    {
        new() { Id = 1, TrackingNumber = "TRK-1001", Origin = "New York, NY", Destination = "Los Angeles, CA", Status = ShipmentStatus.InTransit, CreatedAt = DateTime.UtcNow.AddDays(-3), EstimatedDelivery = DateTime.UtcNow.AddDays(2), RecipientName = "Alice Johnson", Description = "Electronics — 2 boxes" },
        new() { Id = 2, TrackingNumber = "TRK-1002", Origin = "Chicago, IL", Destination = "Houston, TX", Status = ShipmentStatus.Pending, CreatedAt = DateTime.UtcNow.AddDays(-1), EstimatedDelivery = DateTime.UtcNow.AddDays(4), RecipientName = "Bob Smith", Description = "Furniture — 1 pallet" },
        new() { Id = 3, TrackingNumber = "TRK-1003", Origin = "Seattle, WA", Destination = "Miami, FL", Status = ShipmentStatus.PickedUp, CreatedAt = DateTime.UtcNow.AddDays(-2), EstimatedDelivery = DateTime.UtcNow.AddDays(5), RecipientName = "Carol Davis", Description = "Clothing — 3 packages" },
        new() { Id = 4, TrackingNumber = "TRK-1004", Origin = "Boston, MA", Destination = "Denver, CO", Status = ShipmentStatus.OutForDelivery, CreatedAt = DateTime.UtcNow.AddDays(-5), EstimatedDelivery = DateTime.UtcNow, RecipientName = "Dan Lee", Description = "Medical supplies — fragile" },
        new() { Id = 5, TrackingNumber = "TRK-1005", Origin = "San Francisco, CA", Destination = "Atlanta, GA", Status = ShipmentStatus.Delivered, CreatedAt = DateTime.UtcNow.AddDays(-7), EstimatedDelivery = DateTime.UtcNow.AddDays(-1), RecipientName = "Eve Martinez", Description = "Books — 1 box" },
    };

    private static readonly Lock SyncLock = new();

    public Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        lock (SyncLock)
        {
            return Task.FromResult(Shipments.Select(s => Clone(s)).ToList());
        }
    }

    public Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        lock (SyncLock)
        {
            var shipment = Shipments.FirstOrDefault(s =>
                s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
            return Task.FromResult(shipment is null ? null : Clone(shipment));
        }
    }

    public Task<bool> UpdateShipmentStatusAsync(int id, ShipmentStatus newStatus)
    {
        lock (SyncLock)
        {
            var shipment = Shipments.FirstOrDefault(s => s.Id == id);
            if (shipment is null)
                return Task.FromResult(false);

            shipment.Status = newStatus;
            return Task.FromResult(true);
        }
    }

    private static ShipmentDto Clone(ShipmentDto s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = s.Status,
        CreatedAt = s.CreatedAt,
        EstimatedDelivery = s.EstimatedDelivery,
        RecipientName = s.RecipientName,
        Description = s.Description,
    };
}

