                        <p class="fw-semibold @(IsOverdue ? "text-danger" : "")">
                            @(shipment.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "Not available")
                            @if (IsOverdue)
                            {
                                <span> — Overdue</span>
                            }
                        </p>
                    </div>
                </div>

                @* Progress visualization *@
                <div class="mt-4">
                    <h6 class="text-muted mb-3">Shipment Progress</h6>
                    <div class="progress" style="height: 28px;">
                        <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                             role="progressbar"
                             style="width: @(GetProgressPercent(shipment.Status))%"
                             aria-valuenow="@GetProgressPercent(shipment.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @FormatStatus(shipment.Status)
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string trackingInput = "";
    private string lastSearched = "";
    private ShipmentDto? shipment;
    private bool isSearching;
    private bool hasSearched;

    private bool IsOverdue => shipment is { Status: not ShipmentStatus.Delivered and not ShipmentStatus.Cancelled, EstimatedDelivery: not null }
        && shipment.EstimatedDelivery.Value.Date < DateTime.UtcNow.Date;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingInput))
            return;

        isSearching = true;
        lastSearched = trackingInput.Trim();
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        }
        catch
        {
            shipment = null;
        }
        finally
        {
            isSearching = false;
            hasSearched = true;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "Pending",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered",
        ShipmentStatus.Cancelled => "Cancelled",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };
}
