@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<div class="container mt-4">
    <h2>📋 Dispatcher Dashboard</h2>

    <div class="row mb-3 mt-3">
        <div class="col-md-4">
            <label class="form-label fw-semibold">Filter by status</label>
            <select class="form-select" @bind="selectedStatusFilter">
                <option value="">All Statuses</option>
                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                {
                    <option value="@status">@FormatStatus(status)</option>
                }
            </select>
        </div>
        <div class="col-md-4">
            <label class="form-label fw-semibold">Search</label>
            <input type="text" class="form-control" placeholder="Tracking # or destination…"
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4 d-flex align-items-end">
            <button class="btn btn-outline-secondary" @onclick="LoadShipments">
                🔄 Refresh
            </button>
        </div>
    </div>

    @if (isLoading)
    {
        <div class="d-flex justify-content-center my-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading…</span>
            </div>
        </div>
    }
    else if (FilteredShipments.Count == 0)
    {
        <div class="alert alert-info">No shipments match your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover align-middle">
                <thead class="table-dark">
                    <tr>
                        <th>Tracking #</th>
                        <th>Recipient</th>
                        <th>Origin</th>
                        <th>Destination</th>
                        <th>Status</th>
                        <th>Est. Delivery</th>
                        <th>Actions</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var shipment in FilteredShipments)
                    {
                        <tr>
                            <td><code>@shipment.TrackingNumber</code></td>
                            <td>@shipment.RecipientName</td>
                            <td>@shipment.Origin</td>
                            <td>@shipment.Destination</td>
                            <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@FormatStatus(shipment.Status)</span></td>
                            <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                            <td>
                                @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                                {
                                    <select class="form-select form-select-sm d-inline-block w-auto"
                                            value="@shipment.Status"
                                            @onchange="e => OnStatusChange(shipment, e)">
                                        @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                        {
                                            <option value="@status">@FormatStatus(status)</option>
                                        }
                                    </select>
                                }
                                else
                                {
                                    <span class="text-muted">—</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }

    @if (!string.IsNullOrEmpty(statusMessage))
    {
        <div class="alert @(statusMessageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show mt-3">
            @statusMessage
            <button type="button" class="btn-close" @onclick="() => statusMessage = null"></button>
        </div>
    }
</div>

@code {
    private List<ShipmentDto> shipments = [];
    private bool isLoading = true;
    private string selectedStatusFilter = "";
    private string searchTerm = "";
    private string? statusMessage;
    private bool statusMessageIsError;

    private List<ShipmentDto> FilteredShipments => shipments
        .Where(s => string.IsNullOrEmpty(selectedStatusFilter) || s.Status.ToString() == selectedStatusFilter)
        .Where(s => string.IsNullOrEmpty(searchTerm)
            || s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
            || s.RecipientName.Contains(searchTerm, StringComparison.OrdinalIgnoreCase))
        .ToList();

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        isLoading = true;
        statusMessage = null;
        try
        {
            shipments = await ShipmentService.GetAllShipmentsAsync();
        }
        catch
        {
            statusMessage = "Failed to load shipments. Please try again.";
            statusMessageIsError = true;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task OnStatusChange(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var success = await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            if (success)
            {
                shipment.Status = newStatus;
                statusMessage = $"Shipment {shipment.TrackingNumber} updated to {FormatStatus(newStatus)}.";
                statusMessageIsError = false;
            }
            else
            {
                statusMessage = $"Failed to update shipment {shipment.TrackingNumber}.";
                statusMessageIsError = true;
            }
        }
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "Pending",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered",
        ShipmentStatus.Cancelled => "Cancelled",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

