        <div class="col-md-6">
            <div class="input-group">
                <input type="text" class="form-control" placeholder="e.g. TRK-1001"
                       @bind="trackingInput" @bind:event="oninput"
                       @onkeydown="HandleKeyDown" />
                <button class="btn btn-primary" @onclick="SearchShipment" disabled="@isSearching">
                    @if (isSearching)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Search
                </button>
            </div>
        </div>
    </div>

    @if (hasSearched && shipment is null && !isSearching)
    {
        <div class="alert alert-warning">
            <strong>Not found.</strong> No shipment matches tracking number "<strong>@lastSearched</strong>".
            Please check the number and try again.
        </div>
    }

    @if (shipment is not null)
    {
        <div class="card shadow-sm">
            <div class="card-header bg-dark text-white d-flex justify-content-between align-items-center">
                <span><strong>Tracking:</strong> @shipment.TrackingNumber</span>
                <span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@FormatStatus(shipment.Status)</span>
            </div>
            <div class="card-body">
                <div class="row mb-3">
                    <div class="col-md-6">
                        <h6 class="text-muted">Origin</h6>
                        <p class="fw-semibold">@shipment.Origin</p>
                    </div>
                    <div class="col-md-6">
                        <h6 class="text-muted">Destination</h6>
                        <p class="fw-semibold">@shipment.Destination</p>
                    </div>
                </div>
                <div class="row mb-3">
                    <div class="col-md-6">
                        <h6 class="text-muted">Recipient</h6>
                        <p>@shipment.RecipientName</p>
                    </div>
                    <div class="col-md-6">
                        <h6 class="text-muted">Description</h6>
                        <p>@shipment.Description</p>
                    </div>
                </div>
                <div class="row">
                    <div class="col-md-6">
                        <h6 class="text-muted">Shipped On</h6>
                        <p>@shipment.CreatedAt.ToString("MMMM dd, yyyy")</p>
                    </div>
                    <div class="col-md-6">
                        <h6 class="text-muted">Estimated Delivery</h6>
                        <p class="fw-semibold @(IsOverdue ? "text-danger" : "")">
                            @(shipment.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "Not available")
                            @if (IsOverdue)
                            {
                                <span> — Overdue</span>
                            }
                        </p>
                    </div>
                </div>

                @* Progress visualization *@
                <div class="mt-4">
                    <h6 class="text-muted mb-3">Shipment Progress</h6>
                    <div class="progress" style="height: 28px;">
                        <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                             role="progressbar"
                             style="width: @(GetProgressPercent(shipment.Status))%"
                             aria-valuenow="@GetProgressPercent(shipment.Status)"
                             aria-valuemin="0" aria-valuemax="100">
                            @FormatStatus(shipment.Status)
                        </div>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string trackingInput = "";
    private string lastSearched = "";
    private ShipmentDto? shipment;
    private bool isSearching;
    private bool hasSearched;

    private bool IsOverdue => shipment is { Status: not ShipmentStatus.Delivered and not ShipmentStatus.Cancelled, EstimatedDelivery: not null }
        && shipment.EstimatedDelivery.Value.Date < DateTime.UtcNow.Date;

    private async Task SearchShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingInput))
            return;

        isSearching = true;
        lastSearched = trackingInput.Trim();
        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(lastSearched);
        }
        catch
        {
            shipment = null;
        }
        finally
        {
            isSearching = false;
            hasSearched = true;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await SearchShipment();
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "Pending",
        ShipmentStatus.PickedUp => "Picked Up",
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        ShipmentStatus.Delivered => "Delivered",
        ShipmentStatus.Cancelled => "Cancelled",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Cancelled => 100,
        _ => 0
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-primary progress-bar-striped progress-bar-animated"
    };
}

